          return parsed;
        }
      }
    } catch (e) {
      // corrupted — fall through to default
    }
    return JSON.parse(JSON.stringify(DEFAULT_STATE));
  }

  function saveState(state) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  // ---------- state ----------

  let state = loadState();
  const subscribers = [];

  function notify() {
    const snapshot = JSON.parse(JSON.stringify(state));
    subscribers.forEach(cb => cb(snapshot));
  }

  // ---------- API ----------

  window.kanbanAPI = {
    /**
     * Subscribe to state changes.
     * cb is called with a deep copy of state immediately and on every mutation.
     */
    subscribe(cb) {
      subscribers.push(cb);
      cb(JSON.parse(JSON.stringify(state)));
    },

    /**
     * Returns a deep copy of the current state.
     */
    getState() {
      return JSON.parse(JSON.stringify(state));
    },

    /**
     * Create a new card in the given column.
     * @param {string} columnId
     * @param {string} title
     * @returns {object|null} the new card, or null if validation fails
     */
    addCard(columnId, title) {
      const trimmed = (title || '').trim();
      if (!trimmed) return null;
      const column = state.columns.find(c => c.id === columnId);
      if (!column) return null;

      const card = { id: generateId(), title: trimmed, columnId };
      state.cards.push(card);
      saveState(state);
      notify();
      return JSON.parse(JSON.stringify(card));
    },

    /**
     * Delete a card by id.
     * @param {string} cardId
     * @returns {boolean}
     */
    deleteCard(cardId) {
      const idx = state.cards.findIndex(c => c.id === cardId);
      if (idx === -1) return false;
      state.cards.splice(idx, 1);
      saveState(state);
      notify();
      return true;
    },

    /**
     * Move a card to a different column.
     * @param {string} cardId
     * @param {string} targetColumnId
     * @returns {boolean}
     */
    moveCard(cardId, targetColumnId) {
      const card = state.cards.find(c => c.id === cardId);
      if (!card) return false;
      const column = state.columns.find(c => c.id === targetColumnId);
      if (!column) return false;
      if (card.columnId === targetColumnId) return false;
      card.columnId = targetColumnId;
      saveState(state);
      notify();
      return true;
    },

    /**
     * Move a card one step left or right among the ordered columns.
     * @param {string} cardId
     * @param {'left'|'right'} direction
     * @returns {boolean}
     */
    moveCardByDirection(cardId, direction) {
      const card = state.cards.find(c => c.id === cardId);
      if (!card) return false;
      const colIdx = state.columns.findIndex(c => c.id === card.columnId);
      if (colIdx === -1) return false;
      const targetIdx = direction === 'left' ? colIdx - 1 : colIdx + 1;
      if (targetIdx < 0 || targetIdx >= state.columns.length) return false;
      return window.kanbanAPI.moveCard(cardId, state.columns[targetIdx].id);
    }
  };
})();
