        const btnLeft = document.createElement('button');
        btnLeft.className = 'btn-move';
        btnLeft.textContent = '←';
        btnLeft.title = 'Move left';
        btnLeft.disabled = colIndex === 0;
        btnLeft.addEventListener('click', () => {
          window.kanbanAPI.moveCard(card.id, colIds[colIndex - 1]);
        });
        actions.appendChild(btnLeft);

        // Right arrow
        const btnRight = document.createElement('button');
        btnRight.className = 'btn-move';
        btnRight.textContent = '→';
        btnRight.title = 'Move right';
        btnRight.disabled = colIndex === colIds.length - 1;
        btnRight.addEventListener('click', () => {
          window.kanbanAPI.moveCard(card.id, colIds[colIndex + 1]);
        });
        actions.appendChild(btnRight);

        // Delete button
        const btnDel = document.createElement('button');
        btnDel.className = 'btn-delete';
        btnDel.textContent = '✕';
        btnDel.title = 'Delete card';
        btnDel.addEventListener('click', () => {
          window.kanbanAPI.deleteCard(card.id);
        });
        actions.appendChild(btnDel);

        cardEl.appendChild(actions);
        cardsArea.appendChild(cardEl);
      });

      colEl.appendChild(cardsArea);

      // Add card form
      const form = document.createElement('div');
      form.className = 'add-card-form';

      const input = document.createElement('input');
      input.type = 'text';
      input.placeholder = 'New task…';
      input.maxLength = 200;

      const addBtn = document.createElement('button');
      addBtn.type = 'button';
      addBtn.textContent = 'Add';

      const doAdd = () => {
        const val = input.value.trim();
        if (!val) return;
        window.kanbanAPI.addCard(col.id, val);
        // input will be reset on re-render via subscribe callback
      };

      addBtn.addEventListener('click', doAdd);
      input.addEventListener('keydown', e => {
        if (e.key === 'Enter') doAdd();
      });

      form.appendChild(input);
      form.appendChild(addBtn);
      colEl.appendChild(form);

      board.appendChild(colEl);
    });
  }

  // Wire backend subscribe to frontend render
  window.kanbanAPI.subscribe(render);
})();
</script>
</body>
</html>
